import { NextRequest, NextResponse } from 'next/server'
import { processSignals } from '@/lib/agent/scout'

export async function POST(request: NextRequest) {
  try {
    console.log('API: Starting signal scouting process...')
    
    // Trigger the multi-search process
    const result = await processSignals()
    
    console.log('API: Signal scouting process completed', result)
    
    return NextResponse.json({
      success: result.success,
      processed: result.processed,
      errors: result.errors,
      message: result.success 
        ? `Successfully processed ${result.processed} signals` 
        : `Process completed with ${result.errors.length} errors`
    })
    
  } catch (error) {
    console.error('API: Critical error in scout route:', error)
    
    return NextResponse.json({
      success: false,
      processed: 0,
      errors: [`Critical API error: ${error}`],
      message: 'Failed to process signals due to server error'
    }, { status: 500 })
  }
}

export async function GET(request: NextRequest) {
  try {
    return NextResponse.json({
      message: 'Signal scout API endpoint. Use POST to trigger signal processing.',
      endpoints: {
        POST: 'Trigger multi-categorical search and signal processing'
      }
    })
  } catch (error) {
    return NextResponse.json({
      error: 'API endpoint error'
    }, { status: 500 })
  }
}
